const body = $input.first().json.body || $input.first().json;
const caso = body.caso_negocio;
const requeridos = ['latencia_requerida_ms','frecuencia_inferencia','presupuesto_mensual_usd','escalabilidad_requerida','experiencia_tecnica'];
const faltantes = requeridos.filter(k => caso[k] === undefined);
if (faltantes.length > 0) throw new Error(`Campos faltantes: ${faltantes.join(', ')}`);
return [{ json: body }];

const input = $input.first().json;
const caso = input.caso_negocio;

const PESOS = { latencia: 0.25, frecuencia: 0.25, presupuesto: 0.20, escalabilidad: 0.15, experiencia: 0.15 };

const LATENCIA = {
  serverless:  caso.latencia_requerida_ms <= 1000 ? 9 : 4,
  batch:       caso.latencia_requerida_ms <= 1000 ? 1 : 9,
  streaming:   caso.latencia_requerida_ms <= 1000 ? 8 : 6,
  containers:  7,
  sagemaker:   caso.latencia_requerida_ms <= 1000 ? 8 : 7
};

const FRECUENCIA = {
  baja:    { serverless:10, batch:8, streaming:2,  containers:4,  sagemaker:5  },
  media:   { serverless:8,  batch:5, streaming:7,  containers:8,  sagemaker:8  },
  alta:    { serverless:5,  batch:2, streaming:10, containers:9,  sagemaker:9  },
  continua:{ serverless:3,  batch:1, streaming:10, containers:9,  sagemaker:8  }
};

const PRESUPUESTO = {
  serverless: caso.presupuesto_mensual_usd <= 100 ? 10 : 8,
  batch:      caso.presupuesto_mensual_usd <= 100 ? 8  : 7,
  streaming:  caso.presupuesto_mensual_usd <= 100 ? 5  : 7,
  containers: caso.presupuesto_mensual_usd <= 100 ? 4  : 7,
  sagemaker:  caso.presupuesto_mensual_usd <= 100 ? 2  : 6
};

const ESCALABILIDAD = {
  baja:  { serverless:9, batch:8, streaming:5, containers:6, sagemaker:6 },
  media: { serverless:9, batch:6, streaming:8, containers:8, sagemaker:8 },
  alta:  { serverless:7, batch:4, streaming:9, containers:9, sagemaker:9 }
};

const EXPERIENCIA = {
  baja:  { serverless:7, batch:5, streaming:3, containers:2, sagemaker:6 },
  media: { serverless:9, batch:7, streaming:6, containers:6, sagemaker:7 },
  alta:  { serverless:8, batch:8, streaming:9, containers:9, sagemaker:9 }
};

const META = {
  serverless:  { nombre:'Serverless (Lambda + API Gateway)', servicios:['AWS Lambda','API Gateway','S3'] },
  batch:       { nombre:'Batch Processing (S3 + Glue)',       servicios:['Amazon S3','AWS Glue','EventBridge'] },
  streaming:   { nombre:'Streaming (Kinesis + Lambda)',       servicios:['Amazon Kinesis','Lambda','DynamoDB'] },
  containers:  { nombre:'Containers (ECS Fargate + ALB)',     servicios:['ECS Fargate','ALB','ECR'] },
  sagemaker:   { nombre:'SageMaker Managed Endpoint',         servicios:['SageMaker','API Gateway','CloudWatch'] }
};

const frecMap = FRECUENCIA[caso.frecuencia_inferencia] || FRECUENCIA.media;
const escMap  = ESCALABILIDAD[caso.escalabilidad_requerida] || ESCALABILIDAD.media;
const expMap  = EXPERIENCIA[caso.experiencia_tecnica] || EXPERIENCIA.media;

const ranking = Object.keys(META).map(id => {
  const d = {
    latencia:      LATENCIA[id],
    frecuencia:    frecMap[id],
    presupuesto:   PRESUPUESTO[id],
    escalabilidad: escMap[id],
    experiencia:   expMap[id]
  };
  const score = Object.keys(PESOS).reduce((sum, k) => sum + d[k] * PESOS[k], 0);
  return { id, ...META[id], score_total: +score.toFixed(3), desglose: d };
}).sort((a,b) => b.score_total - a.score_total).map((a,i) => ({...a, posicion: i+1}));

const top = ranking[0];
const confianza = Math.min((top.score_total - ranking[1].score_total) / 10 * 5, 1);

return [{ json: {
  recomendacion: {
    arquitectura_id: top.id,
    arquitectura_nombre: top.nombre,
    servicios_aws: top.servicios,
    score: top.score_total,
    confianza: +confianza.toFixed(2),
    justificacion: `'${top.nombre}' obtuvo score ${top.score_total}/10. Destacó en latencia (${top.desglose.latencia}/10), frecuencia '${caso.frecuencia_inferencia}' (${top.desglose.frecuencia}/10) y presupuesto $${caso.presupuesto_mensual_usd}/mes (${top.desglose.presupuesto}/10).`,
    ranking_completo: ranking
  },
  endpoint_demo: $env.API_ENDPOINT || 'https://CONFIGURA_TU_ENDPOINT.execute-api.us-east-1.amazonaws.com/prod/predict',
  datos_prueba: input.datos_prueba,
  timestamp: new Date().toISOString()
}}];

const rec = $('Motor de Recomendación').first().json;
const inference = $input.first().json;
return [{ json: {
  recomendacion: rec.recomendacion,
  resultado_inferencia_aws: {
    riesgo: inference.riesgo,
    probabilidad_riesgo_alto: inference.probabilidad_riesgo_alto,
    modelo_version: inference.modelo_version,
    arquitectura_despliegue: inference.arquitectura_despliegue
  },
  datos_enviados: rec.datos_prueba,
  timestamp: rec.timestamp,
  validacion: {
    arquitectura_recomendada: rec.recomendacion.arquitectura_id,
    endpoint_disponible: true,
    inferencia_exitosa: !!inference.riesgo
  }
}}];
